document.addEventListener('DOMContentLoaded', function () {
  document.querySelectorAll('.mylearningnav .dds__tabs__list a').forEach(anchor => {
    if (!anchor.hasAttribute('href')) {
        const button = anchor.querySelector('button');
        if (button) {
            button.style.color = '#0e0e0e';
        }
        anchor.setAttribute('aria-selected',true);
    }
  });
  const audtype = document.querySelector(".dt-emc-header").getAttribute('data-audtype').toLowerCase();
    //const lldisplay = document.querySelector(".dt-emc-header").getAttribute('data-lldisplay');
    var lldisplay = readCookie('LL_display');
    const titleList = document.querySelectorAll('.dds__tabs__tab__label');
    titleList.forEach(tab => {
      if(tab.title === "Learning Hub"){
        //if(audtype != 'guest' && audtype != 'internal' && lldisplay == 'true'){
        if(audtype == 'guest' || (lldisplay != undefined && lldisplay != null && lldisplay == 'true')){
        	//tab.closest('li').style.display = '';
        	tab.closest('li').classList.remove('hidell');
        }
         else{
          //tab.closest('li').style.display = 'none';
          tab.closest('li').classList.add('hidell');
        }
        var hosturl = window.location.href;
          if (hosturl.indexOf("user-collection.html") !== -1) {
            tab.closest('a').href="/content/dell/"+ countryLocale +"/home/learning-hub.html";
          }
      }
    });
});

